patch:
diff --git a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
index 20528089c000..9640c1a66207 100644
--- a/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
+++ b/llvm/lib/Transforms/Vectorize/LoopVectorize.cpp
@@ -9780,21 +9780,25 @@ preparePlanForEpilogueVectorLoop(VPlan &Plan, Loop *L,
       // FIXME: Improve modeling for canonical IV start values in the epilogue
       // loop.
       using namespace llvm::PatternMatch;
-      Type *IdxTy = IV->getScalarType();
-      PHINode *EPResumeVal = find_singleton<PHINode>(
-          L->getLoopPreheader()->phis(),
-          [&EPI, IdxTy](PHINode &P, bool) -> PHINode * {
-            if (P.getType() == IdxTy &&
-                match(
-                    P.getIncomingValueForBlock(EPI.MainLoopIterationCountCheck),
-                    m_SpecificInt(0)) &&
-                all_of(P.incoming_values(), [&EPI](Value *Inc) {
-                  return Inc == EPI.VectorTripCount ||
-                         match(Inc, m_SpecificInt(0));
-                }))
-              return &P;
-            return nullptr;
-          });
+      PHINode *EPResumeVal = nullptr;
+      for (PHINode &P : L->getLoopPreheader()->phis()) {
+        if (P.getType() != IV->getScalarType())
+          continue;
+        
+        // Check if this could be the canonical IV resume phi.
+        // It should have at least one incoming value of 0 and
+        // at least one incoming value equal to EPI.VectorTripCount.
+        bool HasZero = false;
+        bool HasVectorTC = false;
+        for (Value *Inc : P.incoming_values()) {
+          if (match(Inc, m_SpecificInt(0)))
+            HasZero = true;
+          if (Inc == EPI.VectorTripCount)
+            HasVectorTC = true;
+        }
+        if (HasZero && HasVectorTC)
+          EPResumeVal = &P;
+      }
       assert(EPResumeVal && "must have a resume value for the canonical IV");
       VPValue *VPV = Plan.getOrAddLiveIn(EPResumeVal);
       assert(all_of(IV->users(),

