-                  return Inc == EPI.VectorTripCount ||
-                         match(Inc, m_SpecificInt(0));
-                }))
-              return &P;
-            return nullptr;
-          });
+      PHINode *EPResumeVal = nullptr;
+      for (PHINode &P : L->getLoopPreheader()->phis()) {
+        if (P.getType() != IV->getScalarType())
+          continue;
+        
+        // Check if this is the canonical IV resume phi.
+        // It should have an incoming value from EPI.MainLoopIterationCountCheck with value 0.
+        Value *FromCheck = P.getIncomingValueForBlock(EPI.MainLoopIterationCountCheck);
+        if (!FromCheck || !match(FromCheck, m_SpecificInt(0)))
+          continue;
+        
+        // All other incoming values should be EPI.VectorTripCount.
+        bool AllOtherValuesAreVectorTC = true;
+        for (unsigned i = 0, e = P.getNumIncomingValues(); i < e; i++) {
+          if (P.getIncomingBlock(i) == EPI.MainLoopIterationCountCheck)
+            continue;
+          if (P.getIncomingValue(i) != EPI.VectorTripCount) {
+            AllOtherValuesAreVectorTC = false;
+            break;
+          }
+        }
+        
+        if (AllOtherValuesAreVectorTC)
+          EPResumeVal = &P;
+      }
